}

.artist-root.dark-mode .oeuvre-post-comments-empty,
.artist-root.dark-mode .oeuvre-post-comments-more,
.artist-root.dark-mode .oeuvre-post-comment-date,
.artist-root.dark-mode .oeuvre-post-comment-text {
