}

.artist-root.dark-mode .notifications-menu-button:showing {
    -fx-background-color: #404f7e;
    -fx-border-color: #6878a0;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.20), 14, 0, 0, 4);
}

.artist-root.dark-mode .context-menu.notifications-context-menu {
    -fx-background-color: #1f2a40;
    -fx-border-color: #3f4b6c;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.30), 20, 0.16, 0, 6);
}

.artist-root.dark-mode .context-menu.notifications-context-menu .menu-item {
    -fx-text-fill: #dbe6ff;
}

.artist-root.dark-mode .context-menu.notifications-context-menu .menu-item:hover,
.artist-root.dark-mode .context-menu.notifications-context-menu .menu-item:focused {
    -fx-background-color: #2d3956;
}

.artist-root.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-header {
    -fx-text-fill: #edf2ff;
}

.artist-root.dark-mode .context-menu.notifications-context-menu .separator:horizontal .line {
    -fx-border-color: #3f4b6c;
}

