    -fx-background-color: #1f2a40;
    -fx-border-color: #3f4b6c;
}

.artist-root.dark-mode .collection-menu-trigger:hover {
    -fx-background-color: #2d3956;
}

.artist-root.dark-mode .collection-expand-trigger:hover {
    -fx-background-color: #2d3956;
}

.artist-root.dark-mode .collection-preview-box {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
}

.artist-root.dark-mode .collection-thumbnail-wrapper {
    -fx-border-color: #46557a;
}

.artist-root.dark-mode .collection-preview-empty {
    -fx-text-fill: #b7c4dc;
}

.artist-root.dark-mode .collection-menu {
    -fx-background-color: #24314a;
    -fx-border-color: #3a4767;
}

.artist-root.dark-mode .collection-menu .menu-item .label {
    -fx-text-fill: #dbe6ff;
}

.artist-root.dark-mode .collection-menu .menu-item:focused {
    -fx-background-color: #2d3956;
}

.artist-root.dark-mode .collection-menu .menu-item.collection-menu-delete .label {
    -fx-text-fill: #ff8686;
}

.artist-root.dark-mode .collection-popup {
    -fx-background-color: #1f2a40;
}

.artist-root.dark-mode .popup-title {
    -fx-text-fill: #edf2ff;
}

.artist-root.dark-mode .popup-field-label {
    -fx-text-fill: #b7c4dc;
}

.artist-root.dark-mode .popup-input {
    -fx-background-color: #2a3551;
    -fx-border-color: #43506f;
    -fx-text-fill: #edf2ff;
    -fx-prompt-text-fill: #b7c4dc;
}

.artist-root.dark-mode .popup-input-valid {
    -fx-border-color: #22c55e;
    -fx-background-color: #1f3a2d;
}

.artist-root.dark-mode .popup-input-invalid {
    -fx-border-color: #ef4444;
    -fx-background-color: #3d2126;
}

.artist-root.dark-mode .popup-counter {
    -fx-text-fill: #b7c4dc;
}

/* Form Panel Styles */
.form-panel {
    -fx-background-color: white;
    -fx-background-radius: 16;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 16;
    -fx-effect: dropshadow(gaussian, rgba(0,0,0,0.08), 15, 0, 0, 4);
}

.form-header {
    -fx-border-color: #f0f0f0;
    -fx-border-width: 0 0 1 0;
    -fx-padding: 0 0 16 0;
    -fx-margin: 0 0 16 0;
}

.form-title {
    -fx-font-size: 20px;
    -fx-font-weight: 700;
    -fx-text-fill: #111827;
}

.form-subtitle {
    -fx-font-size: 12px;
    -fx-text-fill: #9ca3af;
}

.field-label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #374151;
}

.input-field {
    -fx-background-color: #f9fafb;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
    -fx-font-size: 13px;
}

.input-field:focused {
    -fx-border-color: #3b82f6;
    -fx-background-color: white;
}

.input-field:hover {
    -fx-border-color: #d1d5db;
}

.image-preview-container {
    -fx-background-color: #f3f4f6;
    -fx-background-radius: 8;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 8;
    -fx-pref-width: 90;
    -fx-pref-height: 60;
    -fx-border-width: 1;
}

.image-placeholder {
    -fx-fill: #e5e7eb;
    -fx-arc-width: 8;
    -fx-arc-height: 8;
}

.pdf-label {
    -fx-font-size: 12px;
    -fx-text-fill: #6b7280;
}

/* Buttons */
.primary-button {
    -fx-background-color: #3b82f6;
    -fx-text-fill: white;
    -fx-background-radius: 10;
    -fx-padding: 12 24;
    -fx-font-size: 14px;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.primary-button:hover {
    -fx-background-color: #2563eb;
}

.primary-button:pressed {
    -fx-background-color: #1d4ed8;
}

.secondary-button {
    -fx-background-color: #f3f4f6;
    -fx-text-fill: #374151;
    -fx-background-radius: 8;
    -fx-padding: 8 16;
    -fx-font-size: 13px;
    -fx-font-weight: 500;
    -fx-cursor: hand;
}

.secondary-button:hover {
    -fx-background-color: #e5e7eb;
}

.danger-button {
    -fx-background-color: #fee2e2;
    -fx-text-fill: #dc2626;
    -fx-background-radius: 10;
    -fx-padding: 12 24;
    -fx-font-size: 14px;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.danger-button:hover {
    -fx-background-color: #fecaca;
}

.danger-button:pressed {
    -fx-background-color: #fca5a5;
}

.danger-button:disabled {
    -fx-background-color: #f3f4f6;
    -fx-text-fill: #9ca3af;
}

.icon-btn {
    -fx-background-color: transparent;
    -fx-border-color: #e5e7eb;
    -fx-border-radius: 8;
    -fx-padding: 8 12;
    -fx-cursor: hand;
}

.icon-btn:hover {
    -fx-background-color: #f3f4f6;
}

.close-btn {
    -fx-background-color: transparent;
    -fx-text-fill: #9ca3af;
    -fx-font-size: 18px;
    -fx-cursor: hand;
    -fx-padding: 4 8;
}

.close-btn:hover {
    -fx-background-color: #fee2e2;
    -fx-text-fill: #dc2626;
}

/* Search field */
.search-field {
    -fx-background-color: #f3f4f6;
    -fx-border-color: transparent;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 14;
}

.search-field:focused {
    -fx-border-color: #3b82f6;
    -fx-background-color: white;
}

/* Cards scroll */
.cards-scroll {
    -fx-background-color: transparent;
}

.cards-scroll > .viewport {
    -fx-background-color: transparent;
}

/* Form scroll */
.form-scroll {
    -fx-background-color: transparent;
    -fx-border-width: 0;
}

.form-scroll > .viewport {
    -fx-background-color: transparent;
}

/* Artist Musiques page */
.users-shell {
    -fx-spacing: 18;
}

.users-panel {
    -fx-background-color: white;
    -fx-background-radius: 20;
    -fx-border-color: #dfe6f0;
    -fx-border-radius: 20;
    -fx-effect: dropshadow(gaussian, rgba(34, 47, 63, 0.08), 16, 0.12, 0, 4);
}

.list-card {
    -fx-background-color: white;
    -fx-background-radius: 14;
    -fx-border-color: #e3e9f2;
    -fx-border-radius: 14;
}

.users-header {
    -fx-alignment: center-left;
}

.users-toolbar {
    -fx-alignment: center-left;
}

.table-search {
    -fx-background-color: #f4f6fa;
    -fx-border-color: #cad2df;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 12 10 12;
    -fx-font-size: 14px;
}

.primary-action-button {
    -fx-background-color: #3d3bc2;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 10;
    -fx-padding: 10 18 10 18;
    -fx-cursor: hand;
}

.primary-action-button:hover {
    -fx-background-color: #3432ad;
}

.users-empty-state {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #6b7e99;
    -fx-padding: 10 0 0 0;
}

.section-title {
    -fx-font-size: 15px;
    -fx-font-weight: 700;
    -fx-text-fill: #2f3e52;
}

.music-panel {
    -fx-background-color: white;
    -fx-background-radius: 20;
    -fx-border-color: #dfe6f0;
    -fx-border-radius: 20;
}

.music-player-card {
    -fx-background-color: #f8faff;
    -fx-background-radius: 12;
    -fx-border-color: #d9e2f0;
    -fx-border-radius: 12;
    -fx-padding: 12;
}

.music-player-title {
    -fx-text-fill: #1f2d53;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
}

.music-player-now {
    -fx-text-fill: #223247;
    -fx-font-size: 13px;
    -fx-font-weight: 700;
}

.music-player-meta {
    -fx-text-fill: #5d7090;
    -fx-font-size: 12px;
}

.music-form-panel {
    -fx-background-color: #f9fbff;
    -fx-background-radius: 14;
    -fx-border-color: #dbe5f2;
    -fx-border-radius: 14;
    -fx-padding: 14;
}

.music-track-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #dfe7f2;
    -fx-border-radius: 12;
    -fx-padding: 10;
    -fx-effect: dropshadow(gaussian, rgba(42, 58, 78, 0.08), 10, 0, 0, 2);
}

.music-track-card-active {
    -fx-border-color: #3d3bc2;
    -fx-effect: none;
}

.users-scroll,
.users-scroll > .viewport,
.users-cards-grid {
    -fx-background-color: transparent;
}

.music-track-title {
    -fx-text-fill: #1c2b3f;
    -fx-font-size: 13px;
    -fx-font-weight: 700;
}

.music-track-meta {
    -fx-text-fill: #5f6f84;
    -fx-font-size: 12px;
}

.music-card-menu-button {
    -fx-background-color: transparent;
    -fx-text-fill: #50617a;
    -fx-font-size: 16px;
    -fx-font-weight: 700;
    -fx-padding: 0 6 0 6;
    -fx-cursor: hand;
}

.music-card-menu-button:hover {
    -fx-background-color: #eef2f8;
    -fx-background-radius: 8;
}

.music-cover-placeholder {
    -fx-background-color: transparent;
    -fx-background-radius: 10;
    -fx-border-color: #dbe5f2;
    -fx-border-radius: 10;
}

.music-cover-placeholder-text {
    -fx-text-fill: #7a8ca6;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.music-cover-image {
    -fx-effect: none;
}

.music-actions-menu {
    -fx-background-color: white;
    -fx-background-radius: 10;
    -fx-border-color: #d9e2ef;
    -fx-border-radius: 10;
    -fx-padding: 4;
    -fx-effect: dropshadow(gaussian, rgba(31, 45, 70, 0.14), 12, 0.14, 0, 3);
}

.music-actions-menu .menu-item {
    -fx-background-color: transparent;
    -fx-background-radius: 8;
    -fx-padding: 7 12 7 12;
}

.music-actions-menu .menu-item .label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #223247;
}

.music-actions-menu .menu-item:focused,
.music-actions-menu .menu-item:hover {
    -fx-background-color: #edf2ff;
}

.music-actions-menu .menu-item.music-actions-delete .label {
    -fx-text-fill: #c62828;
}

.music-actions-menu .menu-item.music-actions-delete:focused,
.music-actions-menu .menu-item.music-actions-delete:hover {
    -fx-background-color: #fff1f2;
}

/* Professional Notifications Menu Styles */

/* Button Styling */
.notifications-menu-button {
    -fx-padding: 0 12 0 12;
    -fx-background-radius: 20;
    -fx-border-radius: 20;
    -fx-background-color: #f0f2ff;
    -fx-border-color: #d4d9e1;
    -fx-text-fill: #4252b8;
    -fx-font-weight: 700;
    -fx-font-size: 16px;
    -fx-border-width: 1;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.12), 8, 0, 0, 2);
    -fx-cursor: hand;
}

.notifications-menu-button:hover {
    -fx-background-color: #e8ebff;
    -fx-border-color: #c4cbe1;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.18), 12, 0, 0, 3);
}

.notifications-menu-button:pressed {
    -fx-translate-y: 1;
}

.notifications-menu-button:showing {
    -fx-background-color: #e3e8ff;
    -fx-border-color: #bfc6ff;
    -fx-effect: dropshadow(gaussian, rgba(66, 82, 184, 0.20), 14, 0, 0, 4);
}

.notifications-menu-button > .arrow-button,
.notifications-menu-button > .arrow-button > .arrow {
    -fx-padding: 0;
    -fx-background-color: transparent;
    -fx-background-insets: 0;
}

/* Context Menu Styling */
.context-menu.notifications-context-menu {
    -fx-background-color: #ffffff;
    -fx-background-radius: 14;
    -fx-border-color: #d9dce3;
    -fx-border-radius: 14;
    -fx-border-width: 1;
    -fx-padding: 8;
    -fx-effect: dropshadow(gaussian, rgba(31, 45, 70, 0.18), 20, 0.16, 0, 6);
}

/* Menu Items */
.context-menu.notifications-context-menu .menu-item {
    -fx-background-color: transparent;
    -fx-background-radius: 10;
    -fx-padding: 10 14 10 14;
    -fx-font-size: 13px;
    -fx-text-fill: #243146;
    -fx-font-weight: 500;
}

.context-menu.notifications-context-menu .menu-item:hover,
.context-menu.notifications-context-menu .menu-item:focused {
    -fx-background-color: #f0f2ff;
    -fx-background-radius: 10;
}

.context-menu.notifications-context-menu .menu-item > .label {
    -fx-text-fill: #243146;
    -fx-font-size: 13px;
    -fx-font-weight: 500;
}

/* Header Item */
.context-menu.notifications-context-menu .menu-item.notifications-header {
    -fx-font-weight: 700;
    -fx-text-fill: #1f2d3d;
    -fx-padding: 12 14 8 14;
    -fx-font-size: 14px;
    -fx-background-color: transparent;
}

.context-menu.notifications-context-menu .menu-item.notifications-header:hover,
.context-menu.notifications-context-menu .menu-item.notifications-header:focused {
    -fx-background-color: transparent;
}

/* Notification Items */
.context-menu.notifications-context-menu .menu-item.notifications-item {
    -fx-padding: 10 14 10 14;
    -fx-font-size: 12px;
    -fx-text-fill: #243146;
}

.context-menu.notifications-context-menu .menu-item.notifications-item:hover {
    -fx-background-color: #f5f7ff;
}

/* Separator */
.context-menu.notifications-context-menu .separator {
    -fx-padding: 4 0;
}

.context-menu.notifications-context-menu .separator:horizontal .line {
    -fx-border-color: #e2e8f2;
    -fx-border-width: 1 0 0 0;
}

/* ==================== DARK MODE STYLES ==================== */

/* Dark Mode Button */
.root.dark-mode .notifications-menu-button,
.dark-mode .notifications-menu-button {
    -fx-background-color: #324261;
    -fx-border-color: #46557a;
    -fx-text-fill: #8ea8ff;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.12), 8, 0, 0, 2);
}

.root.dark-mode .notifications-menu-button:hover,
.dark-mode .notifications-menu-button:hover {
    -fx-background-color: #3a4a72;
    -fx-border-color: #566780;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.18), 12, 0, 0, 3);
}

.root.dark-mode .notifications-menu-button:showing,
.dark-mode .notifications-menu-button:showing {
    -fx-background-color: #404f7e;
    -fx-border-color: #6878a0;
    -fx-effect: dropshadow(gaussian, rgba(142, 168, 255, 0.20), 14, 0, 0, 4);
}

/* Dark Mode Context Menu */
.root.dark-mode .context-menu.notifications-context-menu,
.dark-mode .context-menu.notifications-context-menu {
    -fx-background-color: #1f2a40;
    -fx-border-color: #3f4b6c;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.30), 20, 0.16, 0, 6);
}

.root.dark-mode .context-menu.notifications-context-menu .menu-item,
.dark-mode .context-menu.notifications-context-menu .menu-item {
    -fx-text-fill: #dbe6ff;
}

.root.dark-mode .context-menu.notifications-context-menu .menu-item:hover,
.root.dark-mode .context-menu.notifications-context-menu .menu-item:focused,
.dark-mode .context-menu.notifications-context-menu .menu-item:hover,
.dark-mode .context-menu.notifications-context-menu .menu-item:focused {
    -fx-background-color: #2d3956;
}

.root.dark-mode .context-menu.notifications-context-menu .menu-item > .label,
.dark-mode .context-menu.notifications-context-menu .menu-item > .label {
    -fx-text-fill: #dbe6ff;
}

.root.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-header,
.dark-mode .context-menu.notifications-context-menu .menu-item.notifications-header {
    -fx-text-fill: #edf2ff;
}

.root.dark-mode .context-menu.notifications-context-menu .separator:horizontal .line,
.dark-mode .context-menu.notifications-context-menu .separator:horizontal .line {
    -fx-border-color: #3f4b6c;
}

/* Transitions and Effects */
.notifications-menu-button {
    -fx-transition: all 0.3s ease-in-out;
}

/* Responsive sizing */
.notifications-menu-button {
    -fx-min-width: 40;
    -fx-min-height: 40;
    -fx-pref-width: 40;
    -fx-pref-height: 40;
    -fx-max-width: 40;
    -fx-max-height: 40;
}
